const input = items[0]?.json ?? {};
const headers = input.headers && typeof input.headers === 'object' ? input.headers : {};
const body = input.body && typeof input.body === 'object' ? input.body : input;
const expectedSecret = '__OPS_COMMAND_SHARED_SECRET__';
const providedSecret = String(headers['x-telegram-bot-api-secret-token'] ?? headers['X-Telegram-Bot-Api-Secret-Token'] ?? '').trim();
if (!providedSecret || providedSecret !== expectedSecret) {
  return [];
}

const message = body.message ?? body.edited_message ?? null;
if (!message) {
  return [];
}

const rawText = String(message.text ?? '').trim();
if (!rawText) {
  return [];
}

const [firstToken = '', secondToken = ''] = rawText.split(/\s+/);
const normalizedFirst = firstToken.split('@')[0].toLowerCase();
if (normalizedFirst !== '/ops') {
  return [];
}

const requested = secondToken.trim().toLowerCase() || 'help';
const commandMap = {
  help: 'status.help',
  version: 'status.version',
  drift: 'status.drift',
  overview: 'status.overview',
};
const isSupported = Object.prototype.hasOwnProperty.call(commandMap, requested);

const actorId = String(message.chat?.id ?? '');
if (!actorId) {
  return [];
}

const actorName = message.from?.username || [message.from?.first_name, message.from?.last_name].filter(Boolean).join(' ') || 'telegram';

return [{
  json: {
    reply_chat_id: actorId,
    actor_id: actorId,
    actor_name: actorName,
    raw_text: rawText,
    requested_command: requested,
    unsupported_command: isSupported ? '' : requested,
    command: isSupported ? commandMap[requested] : 'status.help',
    request_id: `ops-${Date.now()}`,
  },
}];

