parameters.jsCode:
const request = $('Parse Ops Command').item.json ?? {};
const api = items[0]?.json ?? {};
const lines = [];

if (request.raw_text) {
  lines.push(`요청: ${request.raw_text}`);
}
if (request.unsupported_command) {
  lines.push(`지원하지 않는 명령: ${request.unsupported_command}`);
}
if (api.summary) {
  lines.push(String(api.summary));
}

const details = Array.isArray(api.details) ? api.details.slice(0, 8) : [];
for (const detail of details) {
  lines.push(`- ${String(detail)}`);
}
if (!lines.length) {
  lines.push('응답을 해석할 수 없습니다.');
}

return [{
  json: {
    reply_chat_id: request.reply_chat_id,
    reply_text: lines.join('\n').slice(0, 3500),
  },
}];
